import { createStreamableUI } from 'ai/rsc';
import { streamText } from 'ai';
import { openai } from '@ai-sdk/openai';

export async function ChatAPI() {
  const { streamText: stream, sendMessage } = createStreamableUI();

  return {
    streamText: async ({ messages }) => {
      const result = await streamText({
        model: openai('gpt-4o'),
        messages,
      });
      return stream(result.textStream);
    },
    sendMessage,
  };
}

import { generateText } from 'ai';
import { z } from 'zod';

const intentSchema = z.object({
  intent: z.enum(['greeting', 'query', 'task', 'goodbye']),
  confidence: z.number().min(0).max(1),
});

export async function classifyIntent(messages: any[]) {
  const { text } = await generateText({
    model: openai('gpt-4o'),
    schema: intentSchema,
    prompt: `Classify user intent from conversation: ${{messages}}`,  
  });
  return text;
}

