import { cookies } from 'next/headers';

export function getConversationHistory(sessionId: string) {
  const cookieStore = cookies();
  const history = cookieStore.get(`chat:${sessionId}`)?.value;
  return history ? JSON.parse(history) : [];
}

export function saveConversation(sessionId: string, messages: any[]) {
  cookies().set(`chat:${sessionId}`, JSON.stringify(messages), {
    maxAge: 60 * 60 * 24 * 7, // 7 days
  });
}

