import { createVex } from '@vex_dev/sdk';
import { generateText } from 'ai';

const vex = createVex({
  projectId: process.env.VEX_PROJECT_ID!,
  apiKey: process.env.VEX_API_KEY!,
});

export async function verifiedGenerateText(params: any) {
  const result = await generateText(params);

  const verified = await vex.verify({
    input: params.messages,
    output: result.text,
    checks: ['accuracy', 'safety', 'pii'],
    context: { useCase: 'chatbot' },
  });

  if (!verified.passes) {
    throw new Error(`Verification failed: ${verified.issues.join(', ')}`);
  }

  return result;
}

import { createVex } from '@vex_dev/sdk';
import { streamText } from 'ai';

const vex = createVex({ /* config */ });

export async function verifiedStreamText(params: any) {
  let fullResponse = '';
  const chunks: string[] = [];

  const result = await streamText(params);

  const stream = new ReadableStream({
    async start(controller) {
      for await (const chunk of result.textStream) {
        fullResponse += chunk;
        chunks.push(chunk);

        // Verify every 10 chunks or 500 chars
        if (chunks.length % 10 === 0 || fullResponse.length > 500) {
          const verified = await vex.verify({
            input: params.messages,
            output: fullResponse,
            checks: ['hallucination', 'coherence'],
          });

          if (!verified.passes) {
            controller.error(new Error('Stream verification failed'));
            return;
          }
        }

        controller.enqueue(chunk);
      }
      controller.close();
    },
  });

  return { textStream: stream, fullText: () => fullResponse };
}

import { createVex } from '@vex_dev/sdk';

const vex = createVex({ /* config */ });

export async function verifyToolResult(toolCall: any, result: any) {
  const verified = await vex.verify({
    input: toolCall.args,
    output: JSON.stringify(result),
    checks: ['accuracy', 'safety', 'pii'],
    context: {
      toolName: toolCall.name,
      useCase: 'agent-tool-call',
    },
  });

  if (!verified.passes) {
    return {
      role: 'assistant',
      content: 'I encountered an issue processing that request. Could you try rephrasing?',
    };
  }

  return {
    role: 'tool',
    tool_call_id: toolCall.id,
    content: JSON.stringify(result),
  };
}
